import{_ as a,c as r,o,a1 as i}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Privacidad y Seguridad | opencode-supermemory","description":"Comprende el mecanismo de protección de privacidad de opencode-supermemory. Aprende a usar etiquetas privadas para desensibilizar datos y configurar API Key de forma segura.","frontmatter":{"title":"Privacidad y Seguridad | opencode-supermemory","subtitle":"Privacidad y Seguridad de Datos: Cómo Proteger tu Información Sensible","sidebarTitle":"Privacidad","description":"Comprende el mecanismo de protección de privacidad de opencode-supermemory. Aprende a usar etiquetas privadas para desensibilizar datos y configurar API Key de forma segura.","tags":["privacidad","seguridad","configuración"],"prerequisite":["start-getting-started"],"order":1},"headers":[],"relativePath":"es/supermemoryai/opencode-supermemory/security/privacy/index.md","filePath":"es/supermemoryai/opencode-supermemory/security/privacy/index.md"}'),t={name:"es/supermemoryai/opencode-supermemory/security/privacy/index.md"};function n(s,e,d,c,l,u){return o(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="privacidad-y-seguridad-de-datos-como-proteger-tu-informacion-sensible" tabindex="-1">Privacidad y Seguridad de Datos: Cómo Proteger tu Información Sensible <a class="header-anchor" href="#privacidad-y-seguridad-de-datos-como-proteger-tu-informacion-sensible" aria-label="Permalink to &quot;Privacidad y Seguridad de Datos: Cómo Proteger tu Información Sensible&quot;">​</a></h1><h2 id="lo-que-podras-hacer-al-terminar" tabindex="-1">Lo que podrás hacer al terminar <a class="header-anchor" href="#lo-que-podras-hacer-al-terminar" aria-label="Permalink to &quot;Lo que podrás hacer al terminar&quot;">​</a></h2><ul><li><strong>Entender a dónde van los datos</strong>: Saber claramente qué datos se subirán a la nube y cuáles quedarán en local.</li><li><strong>Dominar técnicas de desensibilización</strong>: Aprender a usar etiquetas <code>&lt;private&gt;</code> para evitar que información sensible (como contraseñas, claves) se suba.</li><li><strong>Gestionar claves de forma segura</strong>: Aprender a configurar <code>SUPERMEMORY_API_KEY</code> de la manera más segura.</li></ul><h2 id="idea-central" tabindex="-1">Idea Central <a class="header-anchor" href="#idea-central" aria-label="Permalink to &quot;Idea Central&quot;">​</a></h2><p>Al usar opencode-supermemory, comprender el flujo de datos es crucial:</p><ol><li><strong>Almacenamiento en la nube</strong>: Tus memorias (Memories) se almacenan en la base de datos en la nube de Supermemory, no en archivos locales. Esto significa que necesitas conexión de red para acceder a las memorias.</li><li><strong>Desensibilización local</strong>: Para proteger la privacidad, el plugin realiza desensibilización en local <strong>antes</strong> de enviar datos a la nube.</li><li><strong>Control explícito</strong>: El plugin no escanea automáticamente todos los archivos para subir, solo cuando el Agent llama explícitamente la herramienta <code>add</code> o se activa la compresión, el contenido relevante será procesado.</li></ol><h3 id="mecanismo-de-desensibilizacion" tabindex="-1">Mecanismo de desensibilización <a class="header-anchor" href="#mecanismo-de-desensibilizacion" aria-label="Permalink to &quot;Mecanismo de desensibilización&quot;">​</a></h3><p>El plugin incorpora un filtro simple, especializado en identificar etiquetas <code>&lt;private&gt;</code>.</p><ul><li><strong>Entrada</strong>: <code>la contraseña de la base de datos aquí es &lt;private&gt;123456&lt;/private&gt;</code></li><li><strong>Procesamiento</strong>: El plugin detecta la etiqueta, reemplaza el contenido con <code>[REDACTED]</code>.</li><li><strong>Carga</strong>: <code>la contraseña de la base de datos aquí es [REDACTED]</code></li></ul><div class="info custom-block"><p class="custom-block-title">Nota</p><p>Este proceso de procesamiento ocurre dentro del código del plugin, se completa antes de que los datos dejen tu computadora.</p></div><h2 id="sigueme" tabindex="-1">Sígueme <a class="header-anchor" href="#sigueme" aria-label="Permalink to &quot;Sígueme&quot;">​</a></h2><h3 id="paso-1-configurar-api-key-de-forma-segura" tabindex="-1">Paso 1: Configurar API Key de forma segura <a class="header-anchor" href="#paso-1-configurar-api-key-de-forma-segura" aria-label="Permalink to &quot;Paso 1: Configurar API Key de forma segura&quot;">​</a></h3><p>Aunque puedes escribir la API Key directamente en el archivo de configuración, para evitar fugas accidentales (ej: compartir accidentalmente el archivo de configuración con otros), recomendamos entender la lógica de prioridad.</p><p><strong>Regla de prioridad</strong>:</p><ol><li><strong>Archivo de configuración</strong> (<code>~/.config/opencode/supermemory.jsonc</code>): Prioridad más alta.</li><li><strong>Variable de entorno</strong> (<code>SUPERMEMORY_API_KEY</code>): Si no se configura en el archivo, se usa esta variable.</li></ol><p><strong>Práctica recomendada</strong>: Si deseas cambiar flexiblemente o usar en entorno CI/CD, usa variables de entorno. Si eres desarrollador personal, configurar en el archivo JSONC del directorio de usuario también es seguro (porque no está en tu repositorio Git del proyecto).</p><h3 id="paso-2-usar-etiquetas-private" tabindex="-1">Paso 2: Usar etiquetas <code>&lt;private&gt;</code> <a class="header-anchor" href="#paso-2-usar-etiquetas-private" aria-label="Permalink to &quot;Paso 2: Usar etiquetas `&lt;private&gt;`&quot;">​</a></h3><p>Cuando le dices al Agent en lenguaje natural que recuerde cierto contenido que contiene información sensible en la conversación, puedes usar etiquetas <code>&lt;private&gt;</code> para envolver las partes sensibles.</p><p><strong>Demostración de operación</strong>:</p><p>Dile al Agent:</p><blockquote><p>Por favor recuerda, la IP de la base de datos en producción es 192.168.1.10, pero la contraseña de root es <code>&lt;private&gt;SuperSecretPwd!&lt;/private&gt;</code>, no reveles la contraseña.</p></blockquote><p><strong>Deberías ver</strong>: El Agent llamará la herramienta <code>supermemory</code> para guardar la memoria. Aunque la respuesta del Agent puede contener la contraseña (porque está en el contexto), la <strong>memoria realmente guardada en la nube de Supermemory</strong> ya está desensibilizada.</p><h3 id="paso-3-verificar-resultado-de-desensibilizacion" tabindex="-1">Paso 3: Verificar resultado de desensibilización <a class="header-anchor" href="#paso-3-verificar-resultado-de-desensibilizacion" aria-label="Permalink to &quot;Paso 3: Verificar resultado de desensibilización&quot;">​</a></h3><p>Podemos verificar a través de búsqueda si la contraseña anterior realmente no se guardó.</p><p><strong>Operación</strong>: Deja que el Agent busque la memoria anterior:</p><blockquote><p>Busca la contraseña de la base de datos en producción.</p></blockquote><p><strong>Resultado esperado</strong>: El contenido que el Agent recupera de Supermemory debería ser: <code>la IP de la base de datos en producción es 192.168.1.10, pero la contraseña de root es [REDACTED]...</code></p><p>Si el Agent te dice &quot;la contraseña es [REDACTED]&quot;, significa que el mecanismo de desensibilización funciona correctamente.</p><h2 id="errores-comunes" tabindex="-1">Errores comunes <a class="header-anchor" href="#errores-comunes" aria-label="Permalink to &quot;Errores comunes&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Error 1: todo el código se subirá</p><p><strong>Hecho</strong>: El plugin <strong>no</strong> subirá automáticamente todo tu repositorio de código. Solo cuando ejecutas <code>/supermemory-init</code> para realizar escaneo de inicialización, o el Agent decide explícitamente &quot;recordar&quot; cierta lógica de código, se subirá ese segmento específico.</p></div><div class="warning custom-block"><p class="custom-block-title">Error 2: archivos .env se cargan automáticamente</p><p><strong>Hecho</strong>: El plugin lee <code>SUPERMEMORY_API_KEY</code> del entorno del proceso. Si pones un archivo <code>.env</code> en el directorio raíz del proyecto, el plugin <strong>no</strong> lo leerá automáticamente, a menos que la terminal o el programa principal OpenCode que uses lo cargue.</p></div><h2 id="apendice-referencia-del-codigo-fuente" tabindex="-1">Apéndice: Referencia del código fuente <a class="header-anchor" href="#apendice-referencia-del-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencia del código fuente&quot;">​</a></h2><details><summary><strong>Clic para expandir y ver ubicación del código fuente</strong></summary><blockquote><p>Fecha de actualización: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Función</th><th>Ruta del archivo</th><th>Número de línea</th></tr></thead><tbody><tr><td>Lógica de desensibilización de privacidad</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/services/privacy.ts#L1-L13" target="_blank" rel="noreferrer"><code>src/services/privacy.ts</code></a></td><td>1-13</td></tr><tr><td>Carga de API Key</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/config.ts#L90" target="_blank" rel="noreferrer"><code>src/config.ts</code></a></td><td>90</td></tr><tr><td>Llamada de plugin a desensibilización</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L282" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>282</td></tr></tbody></table><p><strong>Funciones clave</strong>:</p><ul><li><code>stripPrivateContent(content)</code>: Ejecuta reemplazo regex, convierte contenido <code>&lt;private&gt;</code> en <code>[REDACTED]</code>.</li><li><code>loadConfig()</code>: Carga archivo de configuración local, prioridad mayor que variables de entorno.</li></ul></details><h2 id="proxima-leccion" tabindex="-1">Próxima lección <a class="header-anchor" href="#proxima-leccion" aria-label="Permalink to &quot;Próxima lección&quot;">​</a></h2><blockquote><p>¡Felicidades por completar el curso principal de opencode-supermemory!</p><p>A continuación puedes:</p><ul><li>Revisar <a href="/docs/opencodedocs/es/supermemoryai/opencode-supermemory/advanced/configuration/">Configuración Avanzada</a> para más opciones de personalización.</li></ul></blockquote>',35)])])}const g=a(t,[["render",n]]);export{m as __pageData,g as default};
